      return;
    const recent = notes.filter((n) => {
      if (!n.updated)
        return true;
      return new Date(n.updated) >= oneMonthAgo;
    });
    const pool = recent.length > 0 ? recent : notes;
    const pick = pool[Math.floor(Math.random() * pool.length)];
